"use client";

import React, { useState, useEffect } from 'react';
import { Plus, Instagram, Sparkles, Zap } from 'lucide-react';
import { Button } from "@/components/ui/button";
import { ServiceCard, MakeupService } from '@/components/ServiceCard';
import { AIGeneratorDialog } from '@/components/AIGeneratorDialog';
import { useToast } from "@/hooks/use-toast";

export default function GirlsStore() {
  const { toast } = useToast();
  const [isSupervisor, setIsSupervisor] = useState(false);
  const [clickCount, setClickCount] = useState(0);
  
  const [services, setServices] = useState<MakeupService[]>(() => [
    { 
      id: '1', 
      name: "Bridal Royalty", 
      price: 150, 
      description: "A signature wedding transformation designed for the modern queen.", 
      imageUrl: "https://images.unsplash.com/photo-1522335789203-aabd1fc54bc9?q=80&w=1200"
    },
    { 
      id: '2', 
      name: "Night Glamour", 
      price: 100, 
      description: "High-contrast editorial aesthetics for the boldest moments.", 
      imageUrl: "https://images.unsplash.com/photo-1512496011212-323a784629c2?q=80&w=1200"
    }
  ]);

  const handleAdminTrigger = () => {
    setClickCount(prev => prev + 1);
  };

  useEffect(() => {
    if (clickCount === 7) {
      const newState = !isSupervisor;
      setIsSupervisor(newState);
      setClickCount(0);
      toast({
        title: newState ? "CORE ACCESS GRANTED" : "STANDARD VIEW",
        description: newState ? "Hassan Deeb Studio core controls active." : "Returning to public gallery.",
      });
    }
  }, [clickCount, isSupervisor, toast]);

  const addService = (name: string, description: string) => {
    const newService: MakeupService = {
      id: Date.now().toString(),
      name,
      price: 100,
      description,
      imageUrl: `https://picsum.photos/seed/${Date.now()}/1200/1600`
    };
    setServices([newService, ...services]);
  };

  const updateService = (updated: MakeupService) => {
    setServices(services.map(s => s.id === updated.id ? updated : s));
  };

  const deleteService = (id: string) => {
    setServices(services.filter(s => s.id !== id));
  };

  return (
    <div className="min-h-screen bg-black text-white flex flex-col selection:bg-primary/30">
      
      {/* Top Signature */}
      <div className="w-full text-center py-4 border-b border-white/5">
        <span className="text-[10px] tracking-[0.6em] text-white/30 font-black uppercase">
          Hassan Deeb Studio Presents
        </span>
      </div>

      {/* Hero Header */}
      <header className="py-16 md:py-24 px-6 text-center border-b border-white/5 relative overflow-hidden">
        <div className="max-w-7xl mx-auto flex flex-col items-center">
          <h1 
            onClick={handleAdminTrigger}
            className="text-7xl md:text-9xl font-headline tracking-[-0.05em] leading-[0.8] mb-8 cursor-pointer select-none"
          >
            GIRLS<br />
            <span className="text-primary italic">STORE</span>
          </h1>

          <div className="flex justify-center gap-8 text-[12px] uppercase tracking-[0.4em] font-black text-primary">
            <span>MUA</span> / <span>HAIR</span> / <span>GLAM</span>
          </div>
          
          {isSupervisor && (
            <div className="mt-12 bg-primary text-black px-8 py-3 rounded-full text-[10px] uppercase tracking-[0.4em] font-black animate-pulse shadow-2xl shadow-primary/20">
              CORE CONTROL ACTIVE
            </div>
          )}
        </div>
      </header>

      {/* Main Feed */}
      <main className="flex-grow max-w-4xl mx-auto px-4 py-8 w-full">
        {isSupervisor && (
          <div className="mb-8 flex flex-col sm:flex-row items-center justify-between gap-6 p-8 bg-white/5 border border-primary/20 rounded-[3rem]">
            <div className="text-center sm:text-left">
              <h2 className="text-xl font-headline text-white italic">Curate the Revolution</h2>
              <p className="text-white/30 text-[10px] uppercase tracking-widest mt-1">Deploy new aesthetic assets.</p>
            </div>
            <div className="flex gap-4">
              <AIGeneratorDialog onGenerated={addService} />
              <Button 
                onClick={() => addService("AESTHETIC V01", "Describe the visual manifesto...")}
                variant="outline"
                className="rounded-full border-white/10 hover:bg-white/5 text-[10px] uppercase tracking-widest h-12 px-8 text-white"
              >
                <Plus className="w-4 h-4 mr-2" /> Manual Add
              </Button>
            </div>
          </div>
        )}

        <div className="space-y-4">
          {services.map(service => (
            <ServiceCard 
              key={service.id} 
              service={service} 
              isSupervisor={isSupervisor}
              onUpdate={updateService}
              onDelete={deleteService}
            />
          ))}

          {isSupervisor && (
            <div 
              onClick={() => addService("NEW REVOLUTION", "MANIFESTO")}
              className="h-[50vh] border-2 border-dashed border-primary/20 rounded-[40px] flex flex-col items-center justify-center text-primary/30 hover:bg-primary/5 transition-all duration-700 cursor-pointer group"
            >
              <div className="p-8 border border-primary/10 rounded-full group-hover:scale-110 transition-transform bg-black shadow-2xl">
                <Plus size={40} strokeWidth={1} />
              </div>
              <span className="text-[10px] uppercase tracking-[0.5em] mt-8 font-black">Expand Collection</span>
            </div>
          )}
        </div>
      </main>

      {/* Footer Revolution */}
      <footer className="py-24 border-t border-white/5 text-center bg-[#050505]">
        <div className="max-w-7xl mx-auto px-6 flex flex-col items-center gap-12">
          
          <div className="flex justify-center gap-16">
            <Instagram size={32} className="text-primary hover:scale-110 transition-all cursor-pointer" />
            <Zap size={32} className="text-white/20" />
          </div>
          
          <div className="inline-block border border-white/5 px-10 py-4 rounded-full bg-white/5">
            <p className="text-[11px] text-white/40 uppercase tracking-[0.6em] font-black">
              WHISH MONEY <span className="mx-4 text-primary">/</span> CRYPTO
            </p>
          </div>
          
          <div className="mt-12 space-y-6">
            <div className="flex items-center justify-center gap-8 text-white/5">
              <div className="h-px w-24 bg-white/5" />
              <span className="text-[10px] tracking-[0.8em] uppercase font-black">Est. 2026</span>
              <div className="h-px w-24 bg-white/5" />
            </div>
            <p className="text-[9px] text-white/20 uppercase tracking-[0.5em] font-black">
              DEVELOPED BY HASSAN DEEB STUDIO • ALL RIGHTS RESERVED
            </p>
          </div>
        </div>
      </footer>
    </div>
  );
}
