"use client";

import React, { useState } from 'react';
import Image from 'next/image';
import { ArrowUpRight, Save, Trash2, Edit2, X, Sparkles } from 'lucide-react';
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";

export interface MakeupService {
  id: string;
  name: string;
  price: number;
  description: string;
  imageUrl: string;
}

interface ServiceCardProps {
  service: MakeupService;
  isSupervisor: boolean;
  onUpdate: (service: MakeupService) => void;
  onDelete: (id: string) => void;
}

export function ServiceCard({ service, isSupervisor, onUpdate, onDelete }: ServiceCardProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [editedService, setEditedService] = useState(service);

  const handleBookNow = () => {
    const phone = "961xxxxxxxx"; 
    const message = `Luxury Booking Request: ${service.name}. Price: ${service.price}$.`;
    window.open(`https://wa.me/${phone}?text=${encodeURIComponent(message)}`, '_blank');
  };

  const handleSave = () => {
    onUpdate(editedService);
    setIsEditing(false);
  };

  return (
    <div className="relative w-full h-[85vh] mb-4 overflow-hidden rounded-[40px] group border border-white/5">
      {/* Background Image */}
      <Image
        src={service.imageUrl}
        alt={service.name}
        fill
        className="object-cover opacity-70 transition-transform duration-1000 group-hover:scale-110"
        data-ai-hint="editorial glamour"
      />

      {/* Content Overlay */}
      <div className="absolute inset-0 bg-gradient-to-t from-black via-black/20 to-transparent flex flex-col justify-end p-8 md:p-12">
        
        {isEditing ? (
          <div className="bg-black/90 backdrop-blur-xl p-8 rounded-[2.5rem] border border-primary/20 space-y-4 animate-in fade-in slide-in-from-bottom-10">
            <h4 className="text-primary text-[10px] uppercase tracking-[0.4em] font-black">Refine Essence</h4>
            <Input 
              className="bg-white/5 border-white/10 text-white font-headline text-2xl h-14"
              value={editedService.name} 
              onChange={(e) => setEditedService({...editedService, name: e.target.value})} 
            />
            <Input 
              className="bg-white/5 border-white/10 text-primary font-bold h-12"
              type="number"
              value={editedService.price} 
              onChange={(e) => setEditedService({...editedService, price: Number(e.target.value)})} 
            />
            <Textarea 
              className="bg-white/5 border-white/10 text-white/60 min-h-[100px]"
              value={editedService.description} 
              onChange={(e) => setEditedService({...editedService, description: e.target.value})} 
            />
            <div className="flex gap-3">
              <Button onClick={handleSave} className="flex-1 bg-primary text-black hover:bg-primary/90 rounded-full h-12 uppercase font-black tracking-widest text-[10px]">
                Commit Changes
              </Button>
              <Button onClick={() => setIsEditing(false)} variant="outline" className="rounded-full h-12 border-white/10 text-white uppercase font-black tracking-widest text-[10px]">
                <X className="w-4 h-4" />
              </Button>
            </div>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="space-y-2">
              <span className="text-primary text-[12px] tracking-[0.4em] font-black uppercase">
                Collection 2026
              </span>
              <h2 className="text-4xl md:text-6xl font-headline text-white leading-none">
                {service.name}
              </h2>
              <p className="text-white/50 font-body text-sm md:text-base max-w-lg">
                {service.description}
              </p>
            </div>

            <div className="flex flex-col sm:flex-row items-center justify-between gap-6 pt-4 border-t border-white/10">
              <div className="text-2xl font-light text-white tracking-tight">
                Starting at <span className="font-bold text-primary">${service.price}</span>
              </div>
              
              <div className="flex gap-4 w-full sm:w-auto">
                {!isSupervisor ? (
                  <Button 
                    onClick={handleBookNow}
                    className="w-full sm:w-auto bg-white text-black hover:bg-primary hover:text-black rounded-full h-16 px-10 text-[12px] uppercase tracking-[0.2em] font-black transition-all shadow-2xl shadow-white/5"
                  >
                    BOOK NOW <ArrowUpRight className="ml-2 w-4 h-4" />
                  </Button>
                ) : (
                  <>
                    <Button 
                      onClick={() => setIsEditing(true)}
                      className="flex-1 sm:flex-none bg-white/5 border border-white/10 text-white hover:bg-white/10 rounded-full h-14 px-8 text-[10px] uppercase font-bold tracking-widest"
                    >
                      <Edit2 className="w-4 h-4 mr-2" /> Edit
                    </Button>
                    <Button 
                      onClick={() => onDelete(service.id)}
                      variant="destructive"
                      className="rounded-full h-14 w-14 p-0 shadow-lg shadow-destructive/20"
                    >
                      <Trash2 className="w-5 h-5" />
                    </Button>
                  </>
                )}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
